import React from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

// Map condition strings to emoji weather icons
const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  const emojiMap: Record<string, string> = {
    sunny: '☀️',
    clear: '☀️',
    cloudy: '☁️',
    overcast: '☁️',
    rainy: '🌧️',
    rain: '🌧️',
    thunderstorm: '⛈️',
    storm: '⛈️',
    snowy: '❄️',
    snow: '❄️',
    windy: '💨',
    wind: '💨',
    foggy: '🌫️',
    fog: '🌫️',
    partly: '⛅',
    hail: '🧊',
    drizzle: '🌦️',
  };

  // Find matching emoji (partial match for flexibility)
  for (const [key, emoji] of Object.entries(emojiMap)) {
    if (conditionLower.includes(key)) {
      return emoji;
    }
  }

  // Default to partly cloudy
  return '⛅';
};

export default function WeatherCard({
  city = 'New York',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '⛅', high: 73, low: 61 },
    { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thu', icon: '☁️', high: 70, low: 59 },
    { day: 'Fri', icon: '☀️', high: 76, low: 63 },
  ],
}: Props) {
  const weatherIcon = getWeatherEmoji(condition);

  return (
    <Card padding={24} shadow="md">
      <Stack direction="vertical" gap={24}>
        {/* Header: City name */}
        <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">
          {city}
        </Text>

        {/* Main weather display */}
        <Stack direction="horizontal" gap={24} align="center" justify="between">
          {/* Left side: Temperature and condition */}
          <Stack direction="vertical" gap={8} align="start">
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                lineHeight: '1',
              }}
            >
              {temperature}
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  marginLeft: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {unit}
              </span>
            </div>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-600, #4b5563)"
              weight="medium"
            >
              {condition}
            </Text>
          </Stack>

          {/* Right side: Large weather icon */}
          <div
            style={{
              fontSize: '64px',
              lineHeight: '1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {weatherIcon}
          </div>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
          }}
        />

        {/* Weather details grid: Humidity and Wind Speed */}
        <Row gap={16} justify="between">
          {/* Humidity */}
          <Stack direction="vertical" gap={6} align="start">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="medium"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-900, #111827)"
              weight="semibold"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={6} align="start">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="medium"
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-900, #111827)"
              weight="semibold"
            >
              {windSpeed} mph
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-neutral-700, #374151)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row
            gap={12}
            justify="start"
            wrap={true}
            style={{
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {forecast.map((item, index) => (
              <div
                key={index}
                style={{
                  flex: '0 0 auto',
                  minWidth: '90px',
                  padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                  backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  gap: 'var(--ggui-spacing-2, 8px)',
                  textAlign: 'center',
                }}
              >
                {/* Day name */}
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-600, #4b5563)"
                  weight="medium"
                >
                  {item.day}
                </Text>

                {/* Weather icon */}
                <div
                  style={{
                    fontSize: '28px',
                    lineHeight: '1',
                  }}
                >
                  {item.icon}
                </div>

                {/* High/Low temps */}
                <Stack
                  direction="horizontal"
                  gap={4}
                  align="center"
                  justify="center"
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="semibold"
                  >
                    {item.high}°
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </div>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

const getWeatherIcon = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('thunder') || conditionLower.includes('storm')) return '⛈️';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  return '🌤️';
};

export default function WeatherCard(props: Props) {
  const {
    city = 'Unknown',
    temperature = 0,
    condition = 'Clear',
    humidity = 0,
    windSpeed = 0,
    unit = '°C',
