            <Text
              variant="heading"
              size="xl"
              style={{
                fontSize: 'var(--ggui-font-size-2xl, 36px)',
                color: 'var(--ggui-text-primary, #000)',
              }}
            >
              {temperature}{unit}
            </Text>
          </Stack>

          {/* Condition text */}
          <Text
            variant="body"
            size="lg"
            style={{
              color: 'var(--ggui-text-secondary, #666)',
              textTransform: 'capitalize',
            }}
          >
            {condition}
          </Text>
        </Stack>

        {/* Weather details grid */}
        <Stack
          gap="md"
          direction="row"
          align="stretch"
          style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            width: '100%',
