            }}
          >
            <Text
              variant="label"
              size="sm"
              style={{ color: 'var(--ggui-text-secondary, #666)' }}
            >
              Humidity
            </Text>
            <Text
              variant="body"
              size="lg"
              style={{
                color: 'var(--ggui-text-primary, #000)',
                fontWeight: 600,
              }}
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack
            gap="sm"
            direction="column"
            align="center"
            style={{
              backgroundColor: 'var(--ggui-background-secondary, #f5f5f5)',
              padding: 'var(--ggui-spacing-md, 16px)',
              borderRadius: 'var(--ggui-radius-md, 8px)',
