          >
            <Text
              variant="label"
              size="sm"
              style={{ color: 'var(--ggui-text-secondary, #666)' }}
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              size="lg"
              style={{
                color: 'var(--ggui-text-primary, #000)',
                fontWeight: 600,
              }}
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* 5-day forecast */}
        {forecast && forecast.length > 0 && (
          <Stack
            gap="sm"
            direction="column"
            style={{
              borderTop: '1px solid var(--ggui-border-color, #e0e0e0)',
