                    <Text
                      variant="body"
                      size="sm"
                      style={{ color: 'var(--ggui-text-secondary, #666)' }}
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

