import React from 'react';
import {
  Box,
  Card,
  Stack,
  Row,
  Text,
  Container,
  Divider,
} from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'sunny',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 70, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 55 },
    { day: 'Thu', icon: '☀️', high: 72, low: 60 },
    { day: 'Fri', icon: '☀️', high: 78, low: 63 },
  ],
}: Props) {
  // Map condition to emoji
  const getWeatherEmoji = (cond: string): string => {
    const conditionMap: Record<string, string> = {
      sunny: '☀️',
      cloudy: '☁️',
      rainy: '🌧️',
      stormy: '⛈️',
      snowy: '❄️',
      windy: '💨',
      foggy: '🌫️',
      clear: '🌙',
    };
    return conditionMap[cond.toLowerCase()] || '🌤️';
  };

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Box
      style={{
        width: '100vw',
        height: '100dvh',
        backgroundColor: 'var(--ggui-color-neutral-50)',
        padding: 'var(--ggui-spacing-6)',
        overflowY: 'auto',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Main Weather Card */}
        <Card padding={24} shadow="md">
          <Stack direction="vertical" gap={20}>
            {/* City and Condition Header */}
            <Stack direction="vertical" gap={8}>
              <Text variant="h2" color="var(--ggui-color-primary-900)">
                {city}
              </Text>
              <Row align="center" gap={12}>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-3xl)',
                  }}
                >
                  {weatherEmoji}
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-neutral-600)"
                  style={{
                    fontSize: 'var(--ggui-font-size-lg)',
                  }}
                >
                  {condition.charAt(0).toUpperCase() + condition.slice(1)}
                </Text>
              </Row>
            </Stack>

            {/* Temperature - Large and Prominent */}
            <Box style={{ textAlign: 'center' }}>
              <Text
                style={{
                  fontSize: 'var(--ggui-font-size-4xl)',
                  fontWeight: 'var(--ggui-font-weight-bold)',
                  color: 'var(--ggui-color-primary-600)',
                  lineHeight: '1.1',
                }}
              >
                {temperature}{unit}
              </Text>
            </Box>

            {/* Humidity and Wind Speed */}
            <Divider orientation="horizontal" margin={16} />

            <Row justify="around" align="center">
              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500)"
                  weight="medium"
                >
                  Humidity
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-xl)',
                    fontWeight: 'var(--ggui-font-weight-semibold)',
                    color: 'var(--ggui-color-neutral-900)',
                  }}
                >
                  {humidity}%
                </Text>
              </Stack>

              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500)"
                  weight="medium"
                >
                  Wind Speed
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-xl)',
                    fontWeight: 'var(--ggui-font-weight-semibold)',
                    color: 'var(--ggui-color-neutral-900)',
                  }}
                >
                  {windSpeed} mph
                </Text>
              </Stack>
            </Row>
          </Stack>
