import React from 'react'
import { Card, Stack, Text, Row, Box, Divider, Button } from '@ggui-ai/design/primitives'

type ForecastItem = {
  day?: string
  condition?: string
  high?: number
  low?: number
}

interface Props {
  city: string
  temperature: number
  condition: string
  humidity: number
  windSpeed: number
  unit: string
  forecast: object[]
  onForecastDayClick?: (index: number, item: object) => void
}

const getWeatherEmoji = (conditionValue: string): string => {
  const normalized = String(conditionValue || '').toLowerCase()
  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️'
  if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️'
  if (normalized.includes('rainy') || normalized.includes('drizzle')) return '🌧️'
  if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️'
  if (normalized.includes('snow')) return '❄️'
  if (normalized.includes('mist') || normalized.includes('fog')) return '🌫️'
  return '🌤️'
}

export default function GeneratedComponent(props: Props) {
  const {
    city = '',
    temperature = 0,
    condition = '',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
    onForecastDayClick,
  } = props

  const safeForecast = Array.isArray(forecast) ? forecast.slice(0, 5) : []
  const clampedHumidity = Math.max(0, Math.min(100, Number.isFinite(humidity) ? humidity : 0))
  const windUnit = unit === 'C' ? 'km/h' : 'mph'
  const currentEmoji = getWeatherEmoji(condition)
  const regionLabel = 'Weather in ' + city

  return (
    <Card
      border
      shadow="md"
      role="region"
      aria-label={regionLabel}
      style={{
        padding: 'var(--ggui-spacing-6, 24px)',
        background: 'var(--ggui-color-neutral-50, #f9fafb)',
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Row justify="between" align="start">
          <Stack direction="vertical" gap={4}>
            <Text variant="h3" weight="semibold" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
              {city}
            </Text>
            <Text variant="body" weight="medium" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
              {condition}
            </Text>
          </Stack>

          <Box
            style={{
              background: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              minWidth: '48px',
              minHeight: '48px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <Text
              variant="h2"
              role="img"
              aria-label={condition || 'weather condition'}
              style={{ color: 'var(--ggui-color-primary-700, #0369a1)' }}
            >
              {currentEmoji}
            </Text>
          </Box>
        </Row>

        <Text variant="h1" weight="bold" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
          {String(temperature) + '°' + unit}
        </Text>

        <Row justify="between" align="center" wrap>
          <Box
            style={{
              background: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              minWidth: '140px',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                Humidity
              </Text>
              <Text variant="body" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
                {String(clampedHumidity) + '%'}
              </Text>
            </Stack>
          </Box>

          <Box
            style={{
              background: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              minWidth: '140px',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                Wind
              </Text>
              <Text variant="body" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
                {String(windSpeed) + ' ' + windUnit}
              </Text>
            </Stack>
          </Box>
        </Row>

        <Divider />

        <Row role="list" wrap gap={8} justify="between" style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
          {safeForecast.map((item, index) => {
            const forecastItem = (item || {}) as ForecastItem
            const day = forecastItem.day ?? ''
            const forecastCondition = forecastItem.condition ?? ''
            const high = forecastItem.high
            const low = forecastItem.low
            const emoji = getWeatherEmoji(forecastCondition)

            const content = (
              <Stack direction="vertical" gap={4}>
                <Text variant="caption" weight="medium" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
                  {day}
                </Text>
                <Text variant="body" role="img" aria-label={forecastCondition || 'forecast condition'}>
                  {emoji}
                </Text>
                <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                  {String(high ?? '--') + '°/' + String(low ?? '--') + '°'}
                </Text>
              </Stack>
            )

            if (onForecastDayClick) {
              return (
                <Button
                  key={String(day) + '-' + String(index)}
                  role="listitem"
                  variant="ghost"
                  size="sm"
                  aria-label={'Forecast for ' + day}
                  onClick={() => onForecastDayClick(index, item)}
                  style={{
                    background: 'var(--ggui-color-neutral-100, #f3f4f6)',
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    minWidth: '92px',
                    textAlign: 'left',
                    transition: 'transform 160ms ease, background-color 160ms ease, border-color 160ms ease',
                    outline: '2px solid transparent',
                    outlineOffset: '2px',
                  }}
                >
                  {content}
                </Button>
              )
            }

            return (
              <Box
                key={String(day) + '-' + String(index)}
                role="listitem"
                style={{
                  background: 'var(--ggui-color-neutral-100, #f3f4f6)',
                  border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  minWidth: '92px',
                }}
              >
                {content}
              </Box>
            )
          })}
        </Row>
      </Stack>
    </Card>
  )
}

