import React from 'react';
import { 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider 
} from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string = '') => {
  const cond = condition.toLowerCase();
  if (cond.includes('sun') || cond.includes('clear')) return '☀️';
  if (cond.includes('cloud')) return '☁️';
  if (cond.includes('rain') || cond.includes('drizzle')) return '🌧️';
  if (cond.includes('thunder') || cond.includes('storm')) return '⛈️';
  if (cond.includes('snow') || cond.includes('ice')) return '❄️';
  if (cond.includes('wind') || cond.includes('mist') || cond.includes('fog')) return '🌫️';
  return '⛅';
};

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = '°C',
  forecast = [
    { day: 'Mon', condition: 'Sunny', high: 24, low: 16 },
    { day: 'Tue', condition: 'Cloudy', high: 21, low: 15 },
    { day: 'Wed', condition: 'Rainy', high: 18, low: 14 },
    { day: 'Thu', condition: 'Cloudy', high: 20, low: 15 },
    { day: 'Fri', condition: 'Sunny', high: 23, low: 17 },
  ]
}: Props) {
  const white = 'var(--ggui-color-neutral-50, #ffffff)';
  const lightBlue = 'var(--ggui-color-primary-100, #e0f2fe)';
  const midBlue = 'var(--ggui-color-primary-200, #bae6fd)';

  return (
    <Card 
      padding="var(--ggui-spacing-6, 24px)" 
      shadow="lg"
      style={{
        maxWidth: '400px',
        background: 'linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))',
        color: white,
        border: 'none',
        borderRadius: 'var(--ggui-shape-radius-xl, 16px)'
      }}
    >
      <Stack gap={24}>
        {/* Header: City & Main Temp */}
        <Stack gap={4} align="center">
          <Text 
            variant="h2" 
            weight="bold" 
            color={white}
          >
            {city}
          </Text>
          <Row align="center" gap={12}>
            <span style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}>
              {getWeatherEmoji(condition)}
            </span>
            <Text 
              style={{ 
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                lineHeight: 1
              }} 
              weight="bold" 
              color={white}
            >
              {Math.round(temperature)}{unit}
            </Text>
          </Row>
          <Text 
            variant="body" 
            weight="medium" 
            color={lightBlue}
          >
            {condition}
          </Text>
        </Stack>

        {/* Details: Humidity & Wind */}
        <Row justify="around" style={{ background: 'rgba(255, 255, 255, 0.1)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', padding: 'var(--ggui-spacing-4, 16px)' }}>
          <Stack align="center" gap={2}>
            <Text variant="caption" color={lightBlue}>HUMIDITY</Text>
            <Text weight="bold" color={white}>{humidity}%</Text>
          </Stack>
          <Divider orientation="vertical" margin={0} style={{ borderColor: 'rgba(255, 255, 255, 0.2)' }} />
          <Stack align="center" gap={2}>
            <Text variant="caption" color={lightBlue}>WIND</Text>
            <Text weight="bold" color={white}>{windSpeed} km/h</Text>
          </Stack>
        </Row>

        {/* Forecast Strip */}
        <Stack gap={12}>
          <Text variant="label" weight="semibold" color={lightBlue}>
            5-DAY FORECAST
          </Text>
          <Row justify="between">
            {forecast.map((item, index) => (
              <Stack key={index} align="center" gap={4} style={{ flex: 1 }}>
                <Text variant="caption" weight="medium" color={lightBlue}>
                  {item.day}
                </Text>
                <span style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }}>
                  {getWeatherEmoji(item.condition)}
                </span>
                <Stack gap={0} align="center">
                  <Text variant="caption" weight="bold" color={white}>
                    {Math.round(item.high)}°
                  </Text>
                  <Text variant="caption" color={midBlue}>
                    {Math.round(item.low)}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
